package main

import (
	"net/http"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	requestCount = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "http_requests_total",
			Help: "Total number of HTTP requests",
		},
		[]string{"user_id", "endpoint", "method", "status_code"},
	)

	requestDuration = prometheus.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "http_request_duration_seconds",
			Help:    "HTTP request duration in seconds",
			Buckets: prometheus.DefBuckets,
		},
		[]string{"user_id", "endpoint", "method"},
	)

	activeUsers = prometheus.NewGaugeVec(
		prometheus.GaugeOpts{
			Name: "active_users",
			Help: "Number of active users",
		},
		[]string{"user_id", "session_id"},
	)

	userOperations = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "user_operations_total",
			Help: "Total number of user operations",
		},
		[]string{"user_id", "operation_type", "status"},
	)
)

func init() {
	prometheus.MustRegister(requestCount)
	prometheus.MustRegister(requestDuration)
	prometheus.MustRegister(activeUsers)
	prometheus.MustRegister(userOperations)
}

func trackUserRequest(userID, endpoint, method, statusCode string, duration time.Duration) {
	requestCount.WithLabelValues(userID, endpoint, method, statusCode).Inc()
	requestDuration.WithLabelValues(userID, endpoint, method).Observe(duration.Seconds())
}

func trackUserOperation(userID, operationType, status string) {
	userOperations.WithLabelValues(userID, operationType, status).Inc()
}

func trackActiveUser(userID, sessionID string) {
	activeUsers.WithLabelValues(userID, sessionID).Inc()
}

func trackInactiveUser(userID, sessionID string) {
	activeUsers.WithLabelValues(userID, sessionID).Dec()
}

func main() {
	http.HandleFunc("/metrics", func(w http.ResponseWriter, r *http.Request) {
		promhttp.Handler().ServeHTTP(w, r)
	})

	http.HandleFunc("/api/users/{user_id}/data", func(w http.ResponseWriter, r *http.Request) {
		userID := r.URL.Path[len("/api/users/") : len(r.URL.Path)-len("/data")]
		start := time.Now()
		
		trackUserRequest(userID, "/api/users/{user_id}/data", r.Method, "200", time.Since(start))
		trackUserOperation(userID, "data_access", "success")
		trackActiveUser(userID, "session_12345")
		
		w.WriteHeader(http.StatusOK)
		w.Write([]byte("Success"))
	})

	http.HandleFunc("/api/users/{user_id}/update", func(w http.ResponseWriter, r *http.Request) {
		userID := r.URL.Path[len("/api/users/") : len(r.URL.Path)-len("/update")]
		start := time.Now()
		
		trackUserRequest(userID, "/api/users/{user_id}/update", r.Method, "200", time.Since(start))
		trackUserOperation(userID, "data_update", "success")
		trackActiveUser(userID, "session_12345")
		
		w.WriteHeader(http.StatusOK)
		w.Write([]byte("Updated"))
	})

	http.ListenAndServe(":8080", nil)
}